  1159→        // Track pointer down position for click detection (F019)
  1160→        pointerDownPosRef.current = { x: e.clientX, y: e.clientY };
  1161→        pointerMovedRef.current = false;
  1162→
  1163→        // Start pan in store
  1164→        canvasStore.dispatch(
  1165→          canvasActions.viewport.startPan({
  1166→            panStart: { x: e.clientX, y: e.clientY },
  1167→            cameraPosAtPanStart: currentCamera,
  1168→          })
  1169→        );
  1170→
  1171→        // Initialize velocity tracking
  1172→        const now = performance.now();
  1173→        lastPointerPosRef.current = { x: e.clientX, y: e.clientY, time: now };
  1174→        velocitySamplesRef.current = [];
  1175→      }
  1176→
  1177→      (e.target as HTMLElement).setPointerCapture(e.pointerId);
  1178→    },
  1179→    [zoom, isInitialized, stopMomentum, stopZoomAnimation]
  1180→  );
  1181→
  1182→  /**
  1183→   * Handle hover detection (F018)
  1184→   * Updates hovered task based on mouse position
  1185→   */
  1186→  const updateHover = useCallback(
  1187→    (e: React.PointerEvent) => {
  1188→      // Only update hover when not panning (avoid expensive calculations during drag)
  1189→      const state = canvasStore.getState();
  1190→      if (state.viewport.isPanning) {
  1191→        // Clear hover during panning
  1192→        if (state.interaction.hoveredTaskId !== null) {
  1193→          canvasStore.dispatch(canvasActions.interaction.setHoveredTask(null));
  1194→        }
  1195→        return;
  1196→      }
  1197→
  1198→      // Get container rect for coordinate conversion
  1199→      const container = containerRef.current;
  1200→      if (!container) return;
  1201→
  1202→      const rect = container.getBoundingClientRect();
  1203→      const camera = state.viewport.camera;
  1204→
  1205→      // Find task under cursor
  1206→      const taskId = findTaskAtPosition(
  1207→        e.clientX,
  1208→        e.clientY,
  1209→        rect,
  1210→        camera.x,
  1211→        camera.y,
  1212→        zoom,
  1213→        canvasSize.width,
  1214→        canvasSize.height,
  1215→        tasks
  1216→      );
  1217→
  1218→      // Only update if changed (avoid unnecessary state updates)
  1219→      if (taskId !== state.interaction.hoveredTaskId) {
  1220→        canvasStore.dispatch(canvasActions.interaction.setHoveredTask(taskId));
  1221→      }
  1222→    },
  1223→    [zoom, canvasSize, tasks]
  1224→  );
  1225→
  1226→  /**
  1227→   * Handle pan move / pinch move
  1228→   *
  1229→   * Now uses canvasStore for pan state - values always current
  1230→   */
  1231→  const handlePointerMove = useCallback(
  1232→    (e: React.PointerEvent) => {
  1233→      const pinch = pinchRef.current;
  1234→
  1235→      // Update pointer position
  1236→      if (pinch.pointers.has(e.pointerId)) {
  1237→        pinch.pointers.set(e.pointerId, { x: e.clientX, y: e.clientY });
  1238→      }
  1239→
  1240→      // Handle pinch gesture
  1241→      if (pinch.active && pinch.pointers.size === 2) {
  1242→        const pointers = Array.from(pinch.pointers.values());
  1243→        const dx = pointers[0].x - pointers[1].x;
  1244→        const dy = pointers[0].y - pointers[1].y;
  1245→        const currentDistance = Math.sqrt(dx * dx + dy * dy);
  1246→
  1247→        if (pinch.initialDistance > 0) {
  1248→          const scale = currentDistance / pinch.initialDistance;
  1249→          const centerX = (pointers[0].x + pointers[1].x) / 2;
  1250→          const centerY = (pointers[0].y + pointers[1].y) / 2;
  1251→          handlePinchZoom(scale, centerX, centerY);
  1252→        }
  1253→        return;
  1254→      }
  1255→
  1256→      // Update hover state (F018) - always run to update cursor
  1257→      updateHover(e);
  1258→
  1259→      // Handle pan - get current state from store
  1260→      const state = canvasStore.getState();
  1261→      if (!state.viewport.isPanning) return;
  1262→
  1263→      const dx = (e.clientX - state.viewport.panStart.x) / zoom;
  1264→      const dy = (e.clientY - state.viewport.panStart.y) / zoom;
  1265→
  1266→      // Detect significant movement (F019: to distinguish click from pan)
  1267→      // Using 8px threshold - movement greater than this is a pan, not a click
  1268→      // Higher threshold helps with touchpad/mouse precision issues
  1269→      const moveX = e.clientX - pointerDownPosRef.current.x;
  1270→      const moveY = e.clientY - pointerDownPosRef.current.y;
  1271→      const moveDistance = Math.sqrt(moveX * moveX + moveY * moveY);
  1272→      if (moveDistance > 8) {
  1273→        pointerMovedRef.current = true;
  1274→      }
  1275→
  1276→      const newX = state.viewport.cameraPosAtPanStart.x - dx;
  1277→      const newY = state.viewport.cameraPosAtPanStart.y + dy;
  1278→
  1279→      const clamped = clampCameraToWorld(newX, newY, zoom);
  1280→
  1281→      // Update pan in store
  1282→      canvasStore.dispatch(canvasActions.viewport.updatePan({ camera: clamped }));
  1283→      notifyViewportChange(clamped.x, clamped.y, zoom);
  1284→
  1285→      // Track velocity samples for momentum
  1286→      const now = performance.now();
  1287→      const worldDx = (e.clientX - lastPointerPosRef.current.x) / zoom;
  1288→      const worldDy = (e.clientY - lastPointerPosRef.current.y) / zoom;
  1289→
  1290→      velocitySamplesRef.current.push({
  1291→        x: worldDx,
  1292→        y: worldDy,
  1293→        time: now,
  1294→      });
  1295→
  1296→      // Keep only recent samples
  1297→      if (velocitySamplesRef.current.length > MOMENTUM_VELOCITY_SAMPLES * 2) {
  1298→        velocitySamplesRef.current = velocitySamplesRef.current.slice(-MOMENTUM_VELOCITY_SAMPLES);
  1299→      }
  1300→
  1301→      lastPointerPosRef.current = { x: e.clientX, y: e.clientY, time: now };
  1302→    },
  1303→    [zoom, clampCameraToWorld, notifyViewportChange, handlePinchZoom, updateHover]
  1304→  );
  1305→
  1306→  /**
  1307→   * Handle pan end / pinch end
  1308→   *
  1309→   * Now uses canvasStore for pan state
  1310→   */
  1311→  const handlePointerUp = useCallback(
  1312→    (e: React.PointerEvent) => {
  1313→      const pinch = pinchRef.current;
  1314→
  1315→      // Remove pointer from tracking
  1316→      pinch.pointers.delete(e.pointerId);
  1317→
  1318→      // Release pointer capture
  1319→      try {
  1320→        (e.target as HTMLElement).releasePointerCapture(e.pointerId);
  1321→      } catch {
  1322→        // Ignore if capture was already released
  1323→      }
  1324→
  1325→      // Reset pinch state when all pointers released
  1326→      if (pinch.pointers.size < 2) {
  1327→        pinch.active = false;
  1328→        pinch.initialDistance = 0;
  1329→      }
  1330→
  1331→      // Handle pan end with momentum - check store for isPanning
  1332→      const state = canvasStore.getState();
  1333→      if (state.viewport.isPanning && pinch.pointers.size === 0) {
  1334→        canvasStore.dispatch(canvasActions.viewport.endPan());
  1335→
  1336→        // Calculate and start momentum
  1337→        const { vx, vy } = calculateAverageVelocity();
  1338→
  1339→        // Only start momentum if velocity is significant
  1340→        const speed = Math.sqrt(vx ** 2 + vy ** 2);
  1341→        if (speed > 0.01) {
  1342→          // Threshold: 0.01 world units per ms
  1343→          startMomentum(vx, vy);
  1344→        }
  1345→      }
  1346→    },
  1347→    [calculateAverageVelocity, startMomentum]
  1348→  );
  1349→
  1350→  /**
  1351→   * Handle double-click to zoom in at click location
  1352→   * Zooms 2x toward the clicked point with smooth animation
  1353→   *
  1354→   * Now uses animateZoomTo which uses the canvasStore
  1355→   */
  1356→  const handleDoubleClick = useCallback(
  1357→    (e: React.MouseEvent) => {
  1358→      if (!isInitialized) return;
  1359→
  1360→      // Stop any active animations
  1361→      stopMomentum();
  1362→      stopZoomAnimation();
  1363→
  1364→      const rect = containerRef.current?.getBoundingClientRect();
  1365→      if (!rect) return;
  1366→
  1367→      // Get current camera from store
  1368→      const currentCamera = canvasStore.getState().viewport.camera;
  1369→
  1370→      // Calculate target zoom (2x, clamped to MAX_ZOOM)
  1371→      const targetZoom = Math.min(zoom * 2, MAX_ZOOM);
  1372→      if (Math.abs(targetZoom - zoom) < 0.001) return;
  1373→
  1374→      // Cursor position relative to canvas center
  1375→      const cursorX = e.clientX - rect.left - rect.width / 2;
  1376→      const cursorY = e.clientY - rect.top - rect.height / 2;
  1377→
  1378→      // Calculate target camera position (zoom toward click point)
  1379→      const worldX = cursorX / zoom + currentCamera.x;
  1380→      const worldY = -cursorY / zoom + currentCamera.y;
  1381→      const newCameraX = worldX - cursorX / targetZoom;
  1382→      const newCameraY = worldY + cursorY / targetZoom;
  1383→
  1384→      const clamped = clampCameraToWorld(newCameraX, newCameraY, targetZoom);
  1385→
  1386→      // Animate with slightly longer duration for double-click (350ms)
  1387→      animateZoomTo(targetZoom, clamped.x, clamped.y, 350);
  1388→    },
  1389→    [zoom, isInitialized, stopMomentum, stopZoomAnimation, clampCameraToWorld, animateZoomTo]
  1390→  );
  1391→
  1392→  /**
  1393→   * Handle click to select/deselect task (F019)
  1394→   * Clicks on tasks select them, clicks on background deselect
  1395→   */
  1396→  const handleClick = useCallback(
  1397→    (e: React.MouseEvent) => {
  1398→      if (!isInitialized) return;
  1399→
  1400→      // Don't process clicks that are part of a pan gesture
  1401→      // If pointer moved significantly between down and up, this is a pan, not a click
  1402→      if (pointerMovedRef.current) {
  1403→        return;
  1404→      }
  1405→
  1406→      const state = canvasStore.getState();
  1407→
  1408→      const container = containerRef.current;
  1409→      if (!container) return;
  1410→
  1411→      const rect = container.getBoundingClientRect();
  1412→      const camera = state.viewport.camera;
  1413→
  1414→      // Find task at click position
  1415→      const taskId = findTaskAtPosition(
  1416→        e.clientX,
  1417→        e.clientY,
  1418→        rect,
  1419→        camera.x,
  1420→        camera.y,
  1421→        zoom,
  1422→        canvasSize.width,
  1423→        canvasSize.height,
  1424→        tasks
  1425→      );
  1426→
  1427→      if (taskId) {
  1428→        // Toggle selection: if clicking same task, deselect; otherwise, select
  1429→        if (taskId === state.interaction.selectedTaskId) {
  1430→          canvasStore.dispatch(canvasActions.interaction.clearSelection());
  1431→        } else {
  1432→          canvasStore.dispatch(canvasActions.interaction.setSelectedTask(taskId));
  1433→        }
  1434→      } else {
  1435→        // Clicked on background: clear selection
  1436→        if (state.interaction.selectedTaskId !== null) {
  1437→          canvasStore.dispatch(canvasActions.interaction.clearSelection());
  1438→        }
  1439→      }
  1440→    },
  1441→    [isInitialized, zoom, canvasSize, tasks]
  1442→  );
  1443→
  1444→  /**
  1445→   * Calculate viewport bounds for frustum culling
  1446→   * This determines which tasks are visible and need to be rendered
  1447→   */
  1448→  const viewportBounds = useMemo<ViewportBounds>(() => {
  1449→    const halfViewX = canvasSize.width / 2 / zoom;
  1450→    const halfViewY = canvasSize.height / 2 / zoom;
  1451→
  1452→    return {
  1453→      minX: cameraPos.x - halfViewX,
  1454→      maxX: cameraPos.x + halfViewX,
  1455→      minY: cameraPos.y - halfViewY,
  1456→      maxY: cameraPos.y + halfViewY,
  1457→    };
  1458→  }, [cameraPos.x, cameraPos.y, canvasSize.width, canvasSize.height, zoom]);
  1459→
  1460→  /**
  1461→   * Handle pointer leave - clear pan and hover state
  1462→   */
  1463→  const handlePointerLeave = useCallback(
  1464→    (e: React.PointerEvent) => {
  1465→      // Handle pan end
  1466→      handlePointerUp(e);
  1467→      // Clear hover state (F018)
  1468→      canvasStore.dispatch(canvasActions.interaction.clearHover());
  1469→    },
  1470→    [handlePointerUp]
  1471→  );
  1472→
  1473→  // Determine cursor style: grabbing when panning, pointer when hovering task, grab otherwise
  1474→  const cursorStyle = isPanning ? 'grabbing' : isHoverable ? 'pointer' : 'grab';
  1475→
  1476→  return (
  1477→    <div
  1478→      ref={containerRef}
  1479→      style={{
  1480→        width: '100%',
  1481→        height: '100%',
  1482→        cursor: cursorStyle,
  1483→        touchAction: 'none',
  1484→      }}
  1485→      onPointerDown={handlePointerDown}
  1486→      onPointerMove={handlePointerMove}
  1487→      onPointerUp={handlePointerUp}
  1488→      onPointerLeave={handlePointerLeave}
  1489→      onDoubleClick={handleDoubleClick}
  1490→      onClick={handleClick}
  1491→    >
  1492→      <Canvas
  1493→        gl={{ antialias: true, alpha: false }}
  1494→        style={{ background: '#f4f4f5' }}
  1495→        orthographic
  1496→        camera={{
  1497→          position: [cameraPos.x, cameraPos.y, 100],
  1498→          zoom: zoom,
  1499→          near: 0.1,
  1500→          far: 1000,
  1501→        }}
  1502→      >
  1503→        <CameraController
  1504→          cameraX={cameraPos.x}
  1505→          cameraY={cameraPos.y}
  1506→          zoom={zoom}
  1507→          worldBounds={worldBounds}
  1508→          isInitialized={isInitialized}
  1509→          onInitialized={handleCameraInitialized}
  1510→          onViewportChange={onViewportChange}
  1511→        />
  1512→
  1513→        <color attach="background" args={['#f4f4f5']} />
  1514→
  1515→        {/* LOD-based layer rendering with smooth transitions */}
  1516→        <LODLayers
  1517→          tasks={tasks}
  1518→          trainCount={trains.length}
  1519→          zoom={zoom}
  1520→          viewportBounds={viewportBounds}
  1521→          hoveredTaskId={hoveredTaskId}
  1522→          selectedTaskId={selectedTaskId}
  1523→        />
  1524→
  1525→        {/* Performance monitor (PERF-001) */}
  1526→        <PerfMonitor visible={perfVisible} currentEvent={perfEvent} />
  1527→      </Canvas>
  1528→    </div>
  1529→  );
  1530→}
