async (page) => {
  // Test F017: Ctrl+Scroll for horizontal pan
  // First, get initial state
  const initialZoom = await page.evaluate(() => {
    const zoomElem = document.querySelector('[class*="NavbarGroup"]');
    const zoomText = document.body.innerText.match(/Zoom: ([\d.]+)x/);
    return zoomText ? zoomText[1] : 'unknown';
  });

  // Dispatch wheel event with ctrlKey on the canvas container
  await page.evaluate(() => {
    // Find canvas container (the element with the wheel listener)
    const canvasContainer = document.querySelector('div[style*="position: relative"]');
    if (!canvasContainer) {
      console.log('Canvas container not found');
      return;
    }

    // Dispatch Ctrl+Scroll (deltaY=200 = scroll down = pan right)
    const event = new WheelEvent('wheel', {
      deltaY: 200,
      deltaX: 0,
      deltaMode: 0,
      ctrlKey: true,
      clientX: 500,
      clientY: 300,
      bubbles: true,
      cancelable: true
    });

    canvasContainer.dispatchEvent(event);
    console.log('Dispatched Ctrl+Scroll event');
  });

  // Wait for potential animation
  await page.waitForTimeout(300);

  // Get final state
  const finalZoom = await page.evaluate(() => {
    const zoomText = document.body.innerText.match(/Zoom: ([\d.]+)x/);
    return zoomText ? zoomText[1] : 'unknown';
  });

  return { initialZoom, finalZoom };
}

